    tlen = __double_decode_array(buf, offset + pos, maxlen - pos, &this->confidence, 1);
    if(tlen < 0) return tlen; else pos += tlen;

    tlen = __int32_t_decode_array(buf, offset + pos, maxlen - pos, &this->confidence_type, 1);
    if(tlen < 0) return tlen; else pos += tlen;

    tlen = __int32_t_decode_array(buf, offset + pos, maxlen - pos, &this->drops_size, 1);
    if(tlen < 0) return tlen; else pos += tlen;

    try {
        this->drops.resize(this->drops_size);
    } catch (...) {
        return -1;
    }
    for (int a0 = 0; a0 < this->drops_size; a0++) {
        tlen = this->drops[a0]._decodeNoHash(buf, offset + pos, maxlen - pos);
        if(tlen < 0) return tlen; else pos += tlen;
    }

    tlen = this->acceleration_vehicle._decodeNoHash(buf, offset + pos, maxlen - pos);
    if(tlen < 0) return tlen; else pos += tlen;

    tlen = this->acceleration_abs._decodeNoHash(buf, offset + pos, maxlen - pos);
    if(tlen < 0) return tlen; else pos += tlen;

    tlen = this->anchor_point_image._decodeNoHash(buf, offset + pos, maxlen - pos);
